#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

struct line {
    int v, w;
};
struct node {
    int x;
    ll l;
    const bool operator<(const node &y) const {
        return (this -> l) > y.l;
    }
};

int n, m;
vector<line> e1[1000005];
vector<line> e2[1000005];
ll f[1000005];
bool v[1000005];
ll ans = 0;

int main() {
    memset(f, 0x3f, sizeof(f));
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        e1[u].push_back({v, w});
        e2[v].push_back({u, w});
    }
    priority_queue<node> q;
    q.push({1, 0});
    f[1] = 0;
    while (!q.empty()) {
        node t = q.top();
        int x = t.x;
        q.pop();
        if (v[x]) continue;
        v[x] = true;
        for (line i : e1[x]) {
            int y = i.v;
            if (f[x] + i.w < f[y]) {
                f[y] = f[x] + i.w;
                q.push({y, f[y]});
            }
        }
    }
    for (int i = 2; i <= n; i++) {
        ans += f[i];
    }
    memset(f, 0x3f, sizeof(f));
    memset(v, 0, sizeof(v));
    q.push({1, 0});
    f[1] = 0;
    while (!q.empty()) {
        node t = q.top();
        int x = t.x;
        q.pop();
        if (v[x]) continue;
        v[x] = true;
        for (line i : e2[x]) {
            int y = i.v;
            if (f[x] + i.w < f[y]) {
                f[y] = f[x] + i.w;
                q.push({y, f[y]});
            }
        }
    }
    for (int i = 2; i <= n; i++) {
        ans += f[i];
    }
    cout << ans;
    return 0;
}
